import React, { useState } from 'react'
import Big from 'big.js'
import clsx from 'clsx'
import Main from '../layouts/main'
import Select from '../components/select'
import { useAsync } from 'react-async-hook'
import { useLocalStorage } from '@rehooks/local-storage'

const pairs = [{ key: 'EURUSD' }]
const currencies = [{ key: 'EUR' }]

const STORAGE_VERSION = 4
const defaultFormState = {
  capital: 1,
  entry: 8000,
  stop: 7000,
  target: 9000,
  risk: 5,
  ethPrice: 300
}

const safeNum = fn => {
  try {
    return fn()
  } catch (err) {
    return '-'
  }
}
const Size = ({ pips, balance, risk }) => {
  try {
    const riskAmount = new Big(balance).times(new Big(risk).div(100)).toFixed(2)
    const valuePerPip = new Big(riskAmount).div(new Big(pips)).toFixed(2)
    const units = new Big(valuePerPip).times(new Big(10000)).toFixed(0)
    const lots = new Big(units).div(new Big(100000)).toFixed(3)
    return (
      <div className='w-1/2 border border-highlight p-2'>
        <span className='text-lgray'>{pips} pips: </span>
        <span>{lots} lots</span>
      </div>
    )
  } catch (err) {
    return <div className='w-1/2 border border-highlight p-2'>-</div>
  }
}
const fetchBTCPrice = async a =>
  (await fetch('https://data.messari.io/api/v1/assets/btc/metrics')).json()

const FXCalculator = () => {
  const btcPrice = useAsync(fetchBTCPrice, [null])
  const [ready, setReady] = useState(true)
  const [pair, setPair] = useState('EURUSD')
  const [currency, setCurrency] = useState('EUR')
  const [account, setAccount] = useLocalStorage('_account', 0.1)
  const [risk, setRisk] = useLocalStorage('_risk', 2)

  const bprice = btcPrice.result
    ? btcPrice.result.data.market_data.price_usd
    : 0
  return (
    <Main
      title='Forex Position Size Calculator with BTC as collateral'
      description='Forex Position Size Calculator with BTC as collateral'>
      <div
        className={clsx({
          'opacity-0': btcPrice.loading || btcPrice.error,
          'opacity-100': btcPrice.result
        })}>
        <h1 className='text-2xl text-left'>
          Forex Position Size Calculator with BTC as collateral
        </h1>
        <div>
          <div className='mt-4'>
            <label className='block mt-1'>
              <span className='text-text'>Account currency</span>
              <Select
                name='currency'
                value={currency}
                onChange={e => setCurrency(e.target.value)}>
                {currencies.map(el => (
                  <option key={el.key} value={el.key}>
                    {el.key}
                  </option>
                ))}
              </Select>
            </label>
            <label className='block mt-1'>
              <span className='text-text'>Pair</span>
              <Select
                name='pair'
                value={pair}
                onChange={e => setPair(e.target.value)}>
                {pairs.map(el => (
                  <option key={el.key} value={el.key}>
                    {el.key}
                  </option>
                ))}
              </Select>
            </label>
            <label className='block mt-1'>
              <span className='text-text'>Account balance</span>
              <input
                className={clsx(
                  'form-input block w-full mt-1 text-text bg-background border border-highlight'
                )}
                type='text'
                inputMode='decimal'
                name={account}
                onChange={e => {
                  setAccount(e.target.value)
                }}
                value={account}
              />
            </label>
            <label className='block mt-1'>
              <span className='text-text'>Risk</span>
              <input
                className={clsx(
                  'form-input block w-full mt-1 text-text bg-background border border-highlight'
                )}
                type='text'
                inputMode='decimal'
                name={risk}
                onChange={e => setRisk(e.target.value)}
                value={risk}
              />
            </label>
            <div className='mt-2'>
              {btcPrice.result &&
                `Current BTC price: ${safeNum(() =>
                  new Big(bprice).toFixed(2)
                )}`}
            </div>
            <div className='mt-2'>
              {btcPrice.result &&
                `Account balance in USD: ${safeNum(() =>
                  new Big(bprice).times(new Big(account)).toFixed(2)
                )}`}
            </div>
          </div>
          <div className='mt-4 flex flex-wrap'>
            {Array.from(Array(50).keys()).map(distance => {
              return (
                <Size
                  key={distance}
                  pips={distance + 1}
                  balance={safeNum(() =>
                    new Big(account).times(new Big(bprice))
                  )}
                  risk={risk}
                />
              )
            })}
          </div>
        </div>
      </div>
    </Main>
  )
}
export default FXCalculator
